# 기존 QA 로드 후 합치기
with open('/home/user/webapp/hanain/src/data/qa.json', 'r', encoding='utf-8') as f:
    data = json.load(f)

# 기존 ID 중복 체크
existing_ids = {q['id'] for q in data['questions']}
new_ids = {q['id'] for q in all_new_qa}
overlap = existing_ids & new_ids
if overlap:
    print(f"⚠️  ID 중복: {overlap}")
else:
    print("✅ ID 중복 없음")

# 병합
data['questions'].extend(all_new_qa)

# 카테고리 count 업데이트
cat_counts = {}
for q in data['questions']:
    cat_counts[q['category']] = cat_counts.get(q['category'], 0) + 1

for cat in data['categories']:
    if cat['id'] in cat_counts:
        cat['count'] = cat_counts[cat['id']]

print(f"\n최종 Q&A 총: {len(data['questions'])}개")
print("카테고리별:")
for cat in data['categories']:
    print(f"  {cat['name']}: {cat['count']}개")

# 저장
with open('/home/user/webapp/hanain/src/data/qa.json', 'w', encoding='utf-8') as f:
    json.dump(data, f, ensure_ascii=False, indent=2)

print("\n✅ qa.json 저장 완료!")
